#!/usr/bin/env node

const { execSync, spawn } = require('child_process');
const fs = require('fs');
const path = require('path');
const os = require('os');

// ============================================================================
// CI/CD Pipeline Script for Node.js Application
// ============================================================================

const CONFIG = {
  nodeVersion: process.env.NODE_VERSION || '20',
  environment: process.env.DEPLOY_ENV || 'production',
  deployTarget: process.env.DEPLOY_TARGET || 'remote',
  deployHost: process.env.DEPLOY_HOST || 'production-server.example.com',
  deployUser: process.env.DEPLOY_USER || 'deploy',
  deployPath: process.env.DEPLOY_PATH || '/var/www/app',
  deployPort: process.env.DEPLOY_PORT || '22',
  appPort: process.env.APP_PORT || '3000',
  healthCheckUrl: process.env.HEALTH_CHECK_URL || 'http://localhost:3000/health',
  healthCheckRetries: parseInt(process.env.HEALTH_CHECK_RETRIES || '10', 10),
  healthCheckInterval: parseInt(process.env.HEALTH_CHECK_INTERVAL || '3000', 10),
  maxTestTimeout: parseInt(process.env.MAX_TEST_TIMEOUT || '300000', 10),
  parallelTests: process.env.PARALLEL_TESTS !== 'false',
  cacheDir: process.env.CACHE_DIR || path.join(os.tmpdir(), 'ci-cache'),
  artifactDir: process.env.ARTIFACT_DIR || './dist',
  rollbackEnabled: process.env.ROLLBACK_ENABLED !== 'false',
  slackWebhook: process.env.SLACK_WEBHOOK_URL || '',
  dryRun: process.env.DRY_RUN === 'true',
  verbose: process.env.VERBOSE === 'true',
};

// ============================================================================
// Utility Functions
// ============================================================================

const COLORS = {
  reset: '\x1b[0m',
  red: '\x1b[31m',
  green: '\x1b[32m',
  yellow: '\x1b[33m',
  blue: '\x1b[34m',
  magenta: '\x1b[35m',
  cyan: '\x1b[36m',
  bold: '\x1b[1m',
};

function log(message, color = 'reset') {
  const timestamp = new Date().toISOString();
  console.log(`${COLORS[color]}[${timestamp}] ${message}${COLORS.reset}`);
}

function logStep(stepName) {
  console.log('');
  log(`${'='.repeat(70)}`, 'cyan');
  log(`  STEP: ${stepName}`, 'bold');
  log(`${'='.repeat(70)}`, 'cyan');
}

function logSuccess(message) {
  log(`✅ ${message}`, 'green');
}

function logError(message) {
  log(`❌ ${message}`, 'red');
}

function logWarning(message) {
  log(`⚠️  ${message}`, 'yellow');
}

function logInfo(message) {
  log(`ℹ️  ${message}`, 'blue');
}

function exec(command, options = {}) {
  const defaultOptions = {
    stdio: CONFIG.verbose ? 'inherit' : 'pipe',
    encoding: 'utf-8',
    env: { ...process.env, ...options.env },
    timeout: options.timeout || 600000, // 10 min default timeout
  };

  const mergedOptions = { ...defaultOptions, ...options };

  if (CONFIG.verbose) {
    logInfo(`Executing: ${command}`);
  }

  if (CONFIG.dryRun && options.dryRunSkip) {
    logWarning(`[DRY RUN] Skipping: ${command}`);
    return '';
  }

  try {
    const result = execSync(command, mergedOptions);
    return typeof result === 'string' ? result.trim() : '';
  } catch (error) {
    if (options.ignoreError) {
      logWarning(`Command failed (ignored): ${command}`);
      return '';
    }
    throw error;
  }
}

function fileExists(filePath) {
  return fs.existsSync(filePath);
}

function measureTime(fn) {
  const start = Date.now();
  const result = fn();
  const duration = ((Date.now() - start) / 1000).toFixed(2);
  return { result, duration };
}

async function measureTimeAsync(fn) {
  const start = Date.now();
  const result = await fn();
  const duration = ((Date.now() - start) / 1000).toFixed(2);
  return { result, duration };
}

function generateBuildId() {
  const gitSha = exec('git rev-parse --short HEAD', { ignoreError: true }) || 'unknown';
  const timestamp = Date.now();
  return `${gitSha}-${timestamp}`;
}

async function sleep(ms) {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

async function sendNotification(message, status = 'info') {
  if (!CONFIG.slackWebhook) return;

  const emoji = {
    info: 'ℹ️',
    success: '✅',
    error: '❌',
    warning: '⚠️',
  }[status] || 'ℹ️';

  const payload = JSON.stringify({
    text: `${emoji} *CI/CD Pipeline* | \`${CONFIG.environment}\`\n${message}`,
  });

  try {
    exec(`curl -s -X POST -H 'Content-type: application/json' --data '${payload}' ${CONFIG.slackWebhook}`, {
      ignoreError: true,
      timeout: 10000,
    });
  } catch {
    logWarning('Failed to send Slack notification');
  }
}

// ============================================================================
// Pipeline Steps
// ============================================================================

class Pipeline {
  constructor() {
    this.buildId = generateBuildId();
    this.startTime = Date.now();
    this.stepTimings = [];
    this.errors = [];
  }

  recordStep(name, duration, status = 'success') {
    this.stepTimings.push({ name, duration, status });
  }

  // --------------------------------------------------------------------------
  // Step 1: Environment Validation
  // --------------------------------------------------------------------------
  validateEnvironment() {
    logStep('Environment Validation');

    // Check Node.js version
    const nodeVersion = process.version;
    logInfo(`Node.js version: ${nodeVersion}`);

    // Check npm/yarn/pnpm availability
    const packageManager = this.detectPackageManager();
    logInfo(`Package manager: ${packageManager}`);

    // Check git
    const gitVersion = exec('git --version', { ignoreError: true });
    if (gitVersion) {
      logInfo(`Git: ${gitVersion}`);
    } else {
      logWarning('Git not found - some features may be unavailable');
    }

    // Check for required environment variables in production
    if (CONFIG.environment === 'production') {
      const requiredVars = ['DEPLOY_HOST', 'DEPLOY_USER'];
      const missing = requiredVars.filter((v) => !process.env[v]);
      if (missing.length > 0 && !CONFIG.dryRun) {
        logWarning(`Missing env vars for production deploy: ${missing.join(', ')}`);
      }
    }

    // Check disk space
    try {
      const diskInfo = exec("df -h . | tail -1 | awk '{print $4}'", { ignoreError: true });
      if (diskInfo) {
        logInfo(`Available disk space: ${diskInfo}`);
      }
    } catch {
      // Non-critical
    }

    logInfo(`Build ID: ${this.buildId}`);
    logInfo(`Environment: ${CONFIG.environment}`);
    logInfo(`Dry run: ${CONFIG.dryRun}`);

    logSuccess('Environment validation complete');
  }

  detectPackageManager() {
    if (fileExists('pnpm-lock.yaml')) {
      this.packageManager = 'pnpm';
      // Ensure pnpm is available
      try {
        exec('pnpm --version');
      } catch {
        logInfo('Installing pnpm...');
        exec('npm install -g pnpm');
      }
      return 'pnpm';
    }
    if (fileExists('yarn.lock')) {
      this.packageManager = 'yarn';
      return 'yarn';
    }
    this.packageManager = 'npm';
    return 'npm';
  }

  // --------------------------------------------------------------------------
  // Step 2: Install Dependencies (with caching)
  // --------------------------------------------------------------------------
  installDependencies() {
    logStep('Install Dependencies');

    const lockFile = {
      npm: 'package-lock.json',
      yarn: 'yarn.lock',
      pnpm: 'pnpm-lock.yaml',
    }[this.packageManager];

    // Generate cache key from lock file
    let cacheHit = false;
    const cacheKey = this.generateCacheKey(lockFile);

    if (cacheKey && this.restoreCache(cacheKey)) {
      cacheHit = true;
      logInfo('Cache restored - running install for verification');
    }

    const installCommands = {
      npm: 'npm ci --prefer-offline --no-audit --no-fund',
      yarn: 'yarn install --frozen-lockfile --non-interactive',
      pnpm: 'pnpm install --frozen-lockfile --prefer-offline',
    };

    const { duration } = measureTime(() => {
      exec(installCommands[this.packageManager], { stdio: 'inherit' });
    });

    // Save cache if it wasn't a cache hit
    if (!cacheHit && cacheKey) {
      this.saveCache(cacheKey);
    }

    logSuccess(`Dependencies installed in ${duration}s ${cacheHit ? '(cache hit)' : ''}`);
    return duration;
  }

  generateCacheKey(lockFile) {
    if (!fileExists(lockFile)) return null;
    try {
      const hash = exec(`md5sum ${lockFile} | cut -d' ' -f1`, { ignoreError: true });
      return hash || null;
    } catch {
      return null;
    }
  }

  restoreCache(cacheKey) {
    const cachePath = path.join(CONFIG.cacheDir, cacheKey);
    const nodeModulesPath = './node_modules';

    if (fs.existsSync(cachePath)) {
      try {
        if (fs.existsSync(nodeModulesPath)) {
          fs.rmSync(nodeModulesPath, { recursive: true, force: true });
        }
        exec(`cp -r ${cachePath} ${nodeModulesPath}`);
        logInfo('Dependency cache restored');
        return true;
      } catch {
        logWarning('Cache restore failed, will do fresh install');
        return false;
      }
    }
    return false;
  }

  saveCache(cacheKey) {
    try {
      if (!fs.existsSync(CONFIG.cacheDir)) {
        fs.mkdirSync(CONFIG.cacheDir, { recursive: true });
      }
      const cachePath = path.join(CONFIG.cacheDir, cacheKey);
      if (!fs.existsSync(cachePath)) {
        exec(`cp -r ./node_modules ${cachePath}`);
        logInfo('Dependency cache saved');
      }
    } catch {
      logWarning('Failed to save cache (non-critical)');
    }
  }

  // --------------------------------------------------------------------------
  // Step 3: Code Quality Checks (Linting)
  // --------------------------------------------------------------------------
  runLinting() {
    logStep('Code Quality Checks');

    const pkg = this.loadPackageJson();
    const scripts = pkg.scripts || {};

    const checks = [];

    // Run lint if available
    if (scripts.lint) {
      checks.push({
        name: 'Linting',
        command: `${this.packageManager} run lint`,
      });
    }

    // Run type checking if available
    if (scripts['type-check'] || scripts.typecheck) {
      const scriptName = scripts['type-check'] ? 'type-check' : 'typecheck';
      checks.push({
        name: 'Type Checking',
        command: `${this.packageManager} run ${scriptName}`,
      });
    } else if (fileExists('tsconfig.json')) {
      checks.push({
        name: 'Type Checking',
        command: 'npx tsc --noEmit',
      });
    }

    // Run format check if available
    if (scripts['format:check'] || scripts['prettier:check']) {
      const scriptName = scripts['format:check'] ? 'format:check' : 'prettier:check';
      checks.push({
        name: 'Format Check',
        command: `${this.packageManager} run ${scriptName}`,
      });
    }

    if (checks.length === 0) {
      logWarning('No linting scripts found - skipping code quality checks');
      return '0';
    }

    const { duration } = measureTime(() => {
      for (const check of checks) {
        logInfo(`Running ${check.name}...`);
        try {
          exec(check.command, { stdio: 'inherit' });
          logSuccess(`${check.name} passed`);
        } catch (error) {
          logError(`${check.name} failed`);
          throw error;
        }
      }
    });

    logSuccess(`Code quality checks completed in ${duration}s`);
    return duration;
  }

  // --------------------------------------------------------------------------
  // Step 4: Run Tests
  // --------------------------------------------------------------------------
  runTests() {
    logStep('Run Tests');

    const pkg = this.loadPackageJson();
    const scripts = pkg.scripts || {};

    if (!scripts.test && !scripts['test:ci']) {
      logWarning('No test script found - skipping tests');
      return '0';
    }

    const testScript = scripts['test:ci'] ? 'test:ci' : 'test';

    // Set test environment variables for speed
    const testEnv = {
      NODE_ENV: 'test',
      CI: 'true',
      FORCE_COLOR: '1',
    };

    // Add parallel test configuration if supported
    if (CONFIG.parallelTests) {
      testEnv.JEST_WORKERS = String(Math.max(1, os.cpus().length - 1));
    }

    const testCommand = `${this.packageManager} run ${testScript}`;

    const { duration } = measureTime(() => {
      try {
        exec(testCommand, {
          stdio: 'inherit',
          env: testEnv,
          timeout: CONFIG.maxTestTimeout,
        });
      } catch (error) {
        logError('Tests failed');
        throw error;
      }
    });

    // Check for coverage thresholds
    if (fileExists('./coverage/coverage-summary.json')) {
      try {
        const coverage = JSON.parse(fs.readFileSync('./coverage/coverage-summary.json', 'utf-8'));
        const total = coverage.total;
        logInfo(`Coverage - Lines: ${total.lines.pct}% | Branches: ${total.branches.pct}% | Functions: ${total.functions.pct}%`);
      } catch {
        // Non-critical
      }
    }

    logSuccess(`Tests completed in ${duration}s`);
    return duration;
  }

  // --------------------------------------------------------------------------
  // Step 5: Security Audit
  // --------------------------------------------------------------------------
  runSecurityAudit() {
    logStep('Security Audit');

    const { duration } = measureTime(() => {
      try {
        const auditCommand = {
          npm: 'npm audit --production --audit-level=high',
          yarn: 'yarn audit --level high',
          pnpm: 'pnpm audit --production --audit-level high',
        }[this.packageManager];

        exec(auditCommand, { stdio: 'inherit', ignoreError: true });
        logSuccess('Security audit passed');
      } catch {
        logWarning('Security audit found vulnerabilities (non-blocking)');
      }
    });

    logSuccess(`Security audit completed in ${duration}s`);
    return duration;
  }

  // --------------------------------------------------------------------------
  // Step 6: Build Application
  // --------------------------------------------------------------------------
  buildApplication() {
    logStep('Build Application');

    const pkg = this.loadPackageJson();
    const scripts = pkg.scripts || {};

    if (!scripts.build) {
      logWarning('No build script found - skipping build step');
      return '0';
    }

    // Clean previous build artifacts
    if (fs.existsSync(CONFIG.artifactDir)) {
      fs.rmSync(CONFIG.artifactDir, { recursive: true, force: true });
      logInfo('Cleaned previous build artifacts');
    }

    const buildEnv = {
      NODE_ENV: 'production',
      BUILD_ID: this.buildId,
      GENERATE_SOURCEMAP: CONFIG.environment === 'production' ? 'false' : 'true',
    };

    const { duration } = measureTime(() => {
      try {
        exec(`${this.packageManager} run build`, {
          stdio: 'inherit',
          env: buildEnv,
        });
      } catch (error) {
        logError('Build failed');
        throw error;
      }
    });

    // Verify build output
    if (fs.existsSync(CONFIG.artifactDir)) {
      const buildSize = exec(`du -sh ${CONFIG.artifactDir} | cut -f1`, { ignoreError: true });
      logInfo(`Build output size: ${buildSize || 'unknown'}`);
    }

    // Write build metadata
    const buildMeta = {
      buildId: this.buildId,
      timestamp: new Date().toISOString(),
      environment: CONFIG.environment,
      nodeVersion: process.version,
      gitCommit: exec('git rev-parse HEAD', { ignoreError: true }) || 'unknown',
      gitBranch: exec('git rev-parse --abbrev-ref HEAD', { ignoreError: true }) || 'unknown',
    };

    const metaPath = path.join(CONFIG.artifactDir, 'build-meta.json');
    try {
      fs.writeFileSync(metaPath, JSON.stringify(buildMeta, null, 2));
      logInfo('Build metadata written');
    } catch {
      // Artifact dir might not exist for non-static builds
      logInfo('Skipped writing build metadata (no artifact directory)');
    }

    logSuccess(`Build completed in ${duration}s`);
    return duration;
  }

  // --------------------------------------------------------------------------
  // Step 7: Create Deployment Package
  // --------------------------------------------------------------------------
  createDeploymentPackage() {
    logStep('Create Deployment Package');

    const packageName = `deploy-${this.buildId}.tar.gz`;
    const packagePath = path.join(os.tmpdir(), packageName);

    // Determine what to include in the deployment package
    const includes = [];

    if (fs.existsSync(CONFIG.artifactDir)) {
      includes.push(CONFIG.artifactDir);
    }

    // Always include essential files
    const essentialFiles = [
      'package.json',
      'package-lock.json',
      'yarn.lock',
      'pnpm-lock.yaml',
      '.env.production',
      '.env',
      'ecosystem.config.js',
      'pm2.config.js',
      'Procfile',
      'Dockerfile',
      'docker-compose.yml',
      'docker-compose.production.yml',
    ].filter((f) => fileExists(f));

    includes.push(...essentialFiles);

    // Include server files if they exist
    const serverDirs = ['server', 'src', 'lib', 'config', 'migrations', 'seeds'].filter((d) => fs.existsSync(d));
    includes.push(...serverDirs);

    if (includes.length === 0) {
      logWarning('No files to package for deployment');
      return { duration: '0', packagePath: null };
    }

    const { duration } = measureTime(() => {
      const excludes = '--exclude=node_modules --exclude=.git --exclude=.env.local --exclude=.env.development --exclude=test --exclude=tests --exclude=__tests__ --exclude=coverage --exclude=.nyc_output';
      exec(`tar ${excludes} -czf ${packagePath} ${includes.join(' ')}`, { stdio: 'inherit' });
    });

    const packageSize = exec(`du -sh ${packagePath} | cut -f1`, { ignoreError: true });
    logInfo(`Deployment package: ${packageName} (${packageSize || 'unknown'})`);
    logSuccess(`Deployment package created in ${duration}s`);

    this.deploymentPackage = packagePath;
    return { duration, packagePath };
  }

  // --------------------------------------------------------------------------
  // Step 8: Deploy to Production
  // --------------------------------------------------------------------------
  async deploy() {
    logStep(`Deploy to ${CONFIG.environment}`);

    if (CONFIG.dryRun) {
      logWarning('[DRY RUN] Skipping actual deployment');
      return '0';
    }

    const deployStrategy = this.detectDeployStrategy();
    logInfo(`Deploy strategy: ${deployStrategy}`);

    let duration;

    switch (deployStrategy) {
      case 'docker':
        ({ duration } = await measureTimeAsync(() => this.deployDocker()));
        break;
      case 'pm2':
        ({ duration } = await measureTimeAsync(() => this.deployPM2()));
        break;
      case 'ssh':
        ({ duration } = await measureTimeAsync(() => this.deploySSH()));
        break;
      case 'local':
        ({ duration } = await measureTimeAsync(() => this.deployLocal()));
        break;
      default:
        logWarning('No deployment strategy detected - skipping deployment');
        return '0';
    }

    logSuccess(`Deployment completed in ${duration}s`);
    return duration;
  }

  detectDeployStrategy() {
    if (fileExists('docker-compose.yml') || fileExists('docker-compose.production.yml') || fileExists('Dockerfile')) {
      return 'docker';
    }
    if (fileExists('ecosystem.config.js') || fileExists('pm2.config.js')) {
      return 'pm2';
    }
    if (CONFIG.deployHost && CONFIG.deployHost !== 'production-server.example.com') {
      return 'ssh';
    }
    return 'local';
  }

  async deployDocker() {
    logInfo('Deploying with Docker...');

    const composeFile = fileExists('docker-compose.production.yml')
      ? 'docker-compose.production.yml'
      : 'docker-compose.yml';

    // Build Docker image
    exec(`docker build -t app:${this.buildId} -t app:latest --build-arg BUILD_ID=${this.buildId} .`, {
      stdio: 'inherit',
    });

    // Tag for registry if configured
    const registry = process.env.DOCKER_REGISTRY;
    if (registry) {
      exec(`docker tag app:${this.buildId} ${registry}/app:${this.buildId}`);
      exec(`docker tag app:latest ${registry}/app:latest`);
      exec(`docker push ${registry}/app:${this.buildId}`);
      exec(`docker push ${registry}/app:latest`);
      logInfo('Docker images pushed to registry');
    }

    // Deploy with docker-compose
    exec(`BUILD_ID=${this.buildId} docker-compose -f ${composeFile} up -d --remove-orphans`, {
      stdio: 'inherit',
    });

    // Wait for container to be healthy
    await this.waitForHealthCheck();
  }

  async deployPM2() {
    logInfo('Deploying with PM2...');

    const configFile = fileExists('ecosystem.config.js') ? 'ecosystem.config.js' : 'pm2.config.js';

    // Check if PM2 is available
    try {
      exec('pm2 --version');
    } catch {
      logInfo('Installing PM2...');
      exec('npm install -g pm2');
    }

    // Install production dependencies
    exec(`${this.packageManager} install --production`, { stdio: 'inherit' });

    // Reload or start the application
    try {
      exec(`pm2 reload ${configFile} --update-env`, { stdio: 'inherit' });
    } catch {
      exec(`pm2 start ${configFile}`, { stdio: 'inherit' });
    }

    // Save PM2 process list
    exec('pm2 save', { ignoreError: true });

    await this.waitForHealthCheck();
  }

  async deploySSH() {
    logInfo(`Deploying via SSH to ${CONFIG.deployHost}...`);

    const sshOpts = `-o StrictHostKeyChecking=no -o ConnectTimeout=10 -p ${CONFIG.deployPort}`;
    const sshTarget = `${CONFIG.deployUser}@${CONFIG.deployHost}`;
    const remotePath = CONFIG.deployPath;
    const releaseDir = `${remotePath}/releases/${this.buildId}`;
    const currentLink = `${remotePath}/current`;

    if (!this.deploymentPackage) {
      throw new Error('No deployment package available');
    }

    // Create release directory
    exec(`ssh ${sshOpts} ${sshTarget} "mkdir -p ${releaseDir}"`, { stdio: 'inherit' });

    // Upload deployment package
    logInfo('Uploading deployment package...');
    exec(`scp ${sshOpts} ${this.deploymentPackage} ${sshTarget}:${releaseDir}/deploy.tar.gz`, {
      stdio: 'inherit',
    });

    // Extract and setup on remote
    const remoteCommands = [
      `cd ${releaseDir}`,
      'tar -xzf deploy.tar.gz',
      'rm deploy.tar.gz',
      'npm ci --production --prefer-offline --no-audit --no-fund 2>/dev/null || npm install --production',
      // Symlink shared resources (logs, uploads, .env, etc.)
      `[ -f ${remotePath}/shared/.env ] && ln -sf ${remotePath}/shared/.env ${releaseDir}/.env`,
      `[ -d ${remotePath}/shared/logs ] && ln -sf ${remotePath}/shared/logs ${releaseDir}/logs`,
      `[ -d ${remotePath}/shared/uploads ] && ln -sf ${remotePath}/shared/uploads ${releaseDir}/uploads`,
      // Update current symlink (atomic deployment)
      `ln -sfn ${releaseDir} ${currentLink}`,
      // Restart application
      `cd ${currentLink} && (pm2 reload ecosystem.config.js --update-env 2>/dev/null || pm2 start ecosystem.config.js 2>/dev/null || echo "Manual restart required")`,
      // Clean up old releases (keep last 5)
      `cd ${remotePath}/releases && ls -t | tail -n +6 | xargs -r rm -rf`,
    ].join(' && ');

    exec(`ssh ${sshOpts} ${sshTarget} '${remoteCommands}'`, { stdio: 'inherit' });

    logInfo('Remote deployment complete');
  }

  async deployLocal() {
    logInfo('Deploying locally...');

    const pkg = this.loadPackageJson();
    const scripts = pkg.scripts || {};

    if (scripts.start) {
      // If there's a running instance, try to gracefully restart
      try {
        exec('pm2 restart all', { ignoreError: true });
      } catch {
        logInfo('Starting application...');
        exec(`NODE_ENV=production ${this.packageManager} start &`, {
          stdio: 'inherit',
          ignoreError: true,
        });
      }
    }

    await this.waitForHealthCheck();
  }

  // --------------------------------------------------------------------------
  // Step 9: Health Check
  // --------------------------------------------------------------------------
  async waitForHealthCheck() {
    logStep('Health Check');

    const url = CONFIG.healthCheckUrl;
    const maxRetries = CONFIG.healthCheckRetries;
    const interval = CONFIG.healthCheckInterval;

    logInfo(`Checking health at ${url} (max ${maxRetries} retries, ${interval}ms interval)`);

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      try {
        const result = exec(`curl -sf -o /dev/null -w '%{http_code}' ${url}`, {
          ignoreError: false,
          timeout: 10000,
        });

        if (result === '200' || result === '204') {
          logSuccess(`Health check passed on attempt ${attempt}`);
          return true;
        }

        logWarning(`Health check returned HTTP ${result} (attempt ${attempt}/${maxRetries})`);
      } catch {
        logWarning(`Health check failed (attempt ${attempt}/${maxRetries})`);
      }

      if (attempt < maxRetries) {
        await sleep(interval);
      }
    }

    logError('Health check failed after all retries');

    if (CONFIG.rollbackEnabled) {
      logWarning('Initiating rollback...');
      await this.rollback();
    }

    throw new Error('Health check failed - deployment may be unhealthy');
  }

  // --------------------------------------------------------------------------
  // Step 10: Rollback
  // --------------------------------------------------------------------------
  async rollback() {
    logStep('Rollback');

    const deployStrategy = this.detectDeployStrategy();

    try {
      switch (deployStrategy) {
        case 'docker': {
          // Roll back to previous Docker image
          exec('docker-compose down', { ignoreError: true });
          logWarning('Docker containers stopped. Manual rollback to previous image may be needed.');
          break;
        }
        case 'pm2': {
          // PM2 has built-in rollback
          exec('pm2 reload ecosystem.config.js --update-env', { ignoreError: true });
          break;
        }
        case 'ssh': {
          const sshOpts = `-o StrictHostKeyChecking=no -p ${CONFIG.deployPort}`;
          const sshTarget = `${CONFIG.deployUser}@${CONFIG.deployHost}`;
          const remotePath = CONFIG.deployPath;

          // Get previous release
          const prevRelease = exec(
            `ssh ${sshOpts} ${sshTarget} "ls -t ${remotePath}/releases | head -2 | tail -1"`,
            { ignoreError: true }
          );

          if (prevRelease) {
            exec(
              `ssh ${sshOpts} ${sshTarget} "ln -sfn ${remotePath}/releases/${prevRelease} ${remotePath}/current && cd ${remotePath}/current && pm2 reload ecosystem.config.js --update-env 2>/dev/null || true"`,
              { stdio: 'inherit' }
            );
            logSuccess(`Rolled back to release: ${prevRelease}`);
          } else {
            logError('No previous release found for rollback');
          }
          break;
        }
        default:
          logWarning('No rollback strategy available');
      }
    } catch (error) {
      logError(`Rollback failed: ${error.message}`);
    }
  }

  // --------------------------------------------------------------------------
  // Helpers
  // --------------------------------------------------------------------------
  loadPackageJson() {
    if (this._packageJson) return this._packageJson;
    try {
      this._packageJson = JSON.parse(fs.readFileSync('package.json', 'utf-8'));
      return this._packageJson;
    } catch {
      return { scripts: {} };
    }
  }

  printSummary() {
    console.log('');
    log('='.repeat(70), 'cyan');
    log('  PIPELINE SUMMARY', 'bold');
    log('='.repeat(70), 'cyan');
    console.log('');

    logInfo(`Build ID:     ${this.buildId}`);
    logInfo(`Environment:  ${CONFIG.environment}`);

    const totalDuration = ((Date.now() - this.startTime) / 1000).toFixed(2);
    logInfo(`Total time:   ${totalDuration}s`);

    console.log('');
    log('Step Timings:', 'cyan');
    for (const step of this.stepTimings) {
      const icon = step.status === 'success' ? '✅' : step.status === 'skipped' ? '⏭️' : '❌';
      console.log(`  ${icon} ${step.name.padEnd(30)} ${step.duration}s`);
    }

    console.log('');

    if (this.errors.length > 0) {
      logError('Pipeline completed with errors:');
      this.errors.forEach((e) => logError(`  - ${e}`));
    } else {
      logSuccess('Pipeline completed successfully! 🚀');
    }

    log('='.repeat(70), 'cyan');
  }

  // --------------------------------------------------------------------------
  // Main Pipeline Execution
  // --------------------------------------------------------------------------
  async run() {
    log('🚀 Starting CI/CD Pipeline', 'bold');
    await sendNotification(`Pipeline started for build \`${this.buildId}\``);

    const steps = [
      { name: 'Environment Validation', fn: () => this.validateEnvironment() },
      { name: 'Install Dependencies', fn: () => this.installDependencies() },
      { name: 'Code Quality Checks', fn: () => this.runLinting() },
      { name: 'Run Tests', fn: () => this.runTests() },
      { name: 'Security Audit', fn: () => this.runSecurityAudit() },
      { name: 'Build Application', fn: () => this.buildApplication() },
      { name: 'Create Deployment Package', fn: () => this.createDeploymentPackage() },
      { name: 'Deploy', fn: () => this.deploy(), async: true },
    ];

    // Parse CLI args for step selection
    const args = process.argv.slice(2);
    const onlySteps = args.filter((a) => a.startsWith('--only=')).map((a) => a.split('=')[1]);
    const skipSteps = args.filter((a) => a.startsWith('--skip=')).map((a) => a.split('=')[1]);
    const skipDeploy = args.includes('--no-deploy');

    for (const step of steps) {
      // Skip deploy if --no-deploy flag
      if (skipDeploy && step.name === 'Deploy') {
        this.recordStep(step.name, '0', 'skipped');
        continue;
      }

      // Handle --only and --skip flags
      if (onlySteps.length > 0 && !onlySteps.some((s) => step.name.toLowerCase().includes(s.toLowerCase()))) {
        this.recordStep(step.name, '0', 'skipped');
        continue;
      }
      if (skipSteps.some((s) => step.name.toLowerCase().includes(s.toLowerCase()))) {
        this.recordStep(step.name, '0', 'skipped');
        continue;
      }

      try {
        let duration;
        if (step.async) {
          const result = await measureTimeAsync(step.fn);
          duration = result.duration;
        } else {
          const result = measureTime(step.fn);
          duration = result.duration;
          // Handle steps that return their own duration
          if (typeof result.result === 'string') {
            duration = result.result !== '0' ? result.result : duration;
          } else if (result.result && typeof result.result === 'object' && result.result.duration) {
            duration = result.result.duration;
          }
        }
        this.recordStep(step.name, duration, 'success');
      } catch (error) {
        this.recordStep(step.name, '0', 'failed');
        this.errors.push(`${step.name}: ${error.message}`);
        logError(`Step "${step.name}" failed: ${error.message}`);
        await sendNotification(`Pipeline failed at step: ${step.name}\nError: ${error.message}`, 'error');
        this.printSummary();
        process.exit(1);
      }
    }

    await sendNotification(`Pipeline completed successfully! Build: \`${this.buildId}\``, 'success');
    this.printSummary();

    // Clean up temporary files
    if (this.deploymentPackage && fs.existsSync(this.deploymentPackage)) {
      fs.unlinkSync(this.deploymentPackage);
    }
  }
}

// ============================================================================
// CLI Help
// ============================================================================

function printHelp() {
  console.log(`
${COLORS.bold}Node.js CI/CD Pipeline${COLORS.reset}

${COLORS.cyan}Usage:${COLORS.reset}
  node pipeline.js [options]

${COLORS.cyan}Options:${COLORS.reset}
  --help              Show this help message
  --no-deploy         Skip deployment step
  --only=<step>       Run only matching steps (can be used multiple times)
  --skip=<step>       Skip matching steps (can be used multiple times)

${COLORS.cyan}Environment Variables:${COLORS.reset}
  NODE_VERSION          Expected Node.js version (default: 20)
  DEPLOY_ENV            Deployment environment (default: production)
  DEPLOY_HOST           Remote host for SSH deployment
  DEPLOY_USER           Remote user for SSH deployment
  DEPLOY_PATH           Remote path for deployment (default: /var/www/app)
  DEPLOY_PORT           SSH port (default: 22)
  APP_PORT              Application port (default: 3000)
  HEALTH_CHECK_URL      Health check URL (default: http://localhost:3000/health)
  HEALTH_CHECK_RETRIES  Max health check retries (default: 10)
  DOCKER_REGISTRY       Docker registry URL for pushing images
  SLACK_WEBHOOK_URL     Slack webhook for notifications
  DRY_RUN               Set to 'true' for dry run mode
  VERBOSE               Set to 'true' for verbose output
  PARALLEL_TESTS        Set to 'false' to disable parallel tests
  ROLLBACK_ENABLED      Set to 'false' to disable auto-rollback
  CACHE_DIR             Custom cache directory

${COLORS.cyan}Examples:${COLORS.reset}
  # Full pipeline
  node pipeline.js

  # Build only (no deploy)
  node pipeline.js --no-deploy

  # Run only tests
  node pipeline.js --only=test

  # Skip linting and security audit
  node pipeline.js --skip=quality --skip=security

  # Dry run
  DRY_RUN=true node pipeline.js

  # Deploy to staging
  DEPLOY_ENV=staging DEPLOY_HOST=staging.example.com node pipeline.js
`);
}

// ============================================================================
// Entry Point
// ============================================================================

if (process.argv.includes('--help') || process.argv.includes('-h')) {
  printHelp();
  process.exit(0);
}

const pipeline = new Pipeline();
pipeline.run().catch((error) => {
  logError(`Pipeline crashed: ${error.message}`);
  if (CONFIG.verbose) {
    console.error(error);
  }
  process.exit(1);
});